class GraphQuery{constructor(t={},e=[]){this.nodes=t,this.edges=e,this.outAdjacency={},this.inAdjacency={},this.edges.forEach(t=>{this.outAdjacency[t.from]||(this.outAdjacency[t.from]=[]),this.outAdjacency[t.from].push(t),this.inAdjacency[t.to]||(this.inAdjacency[t.to]=[]),this.inAdjacency[t.to].push(t)})}getNode(t){return this.nodes[t]||null}getNeighbors(t,e=null){const n=this.outAdjacency[t]||[];return(e?n.filter(t=>t.relation===e):n).map(t=>({id:t.to,node:this.nodes[t.to]||null,relation:t.relation,weight:t.weight||null,context:t.context||null}))}getIncoming(t,e=null){const n=this.inAdjacency[t]||[];return(e?n.filter(t=>t.relation===e):n).map(t=>({id:t.from,node:this.nodes[t.from]||null,relation:t.relation,weight:t.weight||null,context:t.context||null}))}getCompaniesForIntent(t){const e=t.startsWith("intent-")?t:`intent-${t}`;return this.getIncoming(e,"offers")}getCollaborators(t){return this.getNeighbors(t,"collaborated_with")}getRecommendations(t){return this.getNeighbors(t,"recommends_with")}getAreas(t){return this.getNeighbors(t,"located_in")}getCollaboratorsOffering(t,e){const n=this.getCollaborators(t).map(t=>t.id),o=this.getCompaniesForIntent(e).map(t=>t.id);return n.filter(t=>o.includes(t)).map(t=>({id:t,node:this.nodes[t]||null}))}}"undefined"!=typeof module&&module.exports?module.exports=GraphQuery:window.GraphQuery=GraphQuery;